      ) : (
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={handleLogin} onRegister={handleRegister} />} />
          <Route path="*" element={<Navigate replace to="/login" state={{ from: location }} />} />
        </Routes>
      )}
    </div>
  );
};

